var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"허억…!","JPN":"はあっ……！","ENG":"*Gasp…!*","TWN":"哈啊…！"},"stage":{"bg":"VOID","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_WATER"},{"id":"L4_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"쿨럭, 쿨럭…","JPN":"ゲホッ、ゲホッ……","ENG":"*Cough* *Cough…*","TWN":"咳、咳咳…"},"stage":{"bg":"VOID","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_HATE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"여긴 어디지?","JPN":"ここはどこだ？","ENG":"Where am I?","TWN":"這裡是哪裡？"},"stage":{"bg":"VOID","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":null,"text":{"KOREA":"너는 범에게 먹혔다.","JPN":"お前は虎に食われた。","ENG":"You were devoured by the Tiger.","TWN":"你被老虎給吞了。"},"stage":{"bg":"VOID","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L9_1","type":"dialog","speaker":null,"text":{"KOREA":"이곳은 먹으로 가득 들어찬 범의 뱃속이지.","JPN":"そしてここは、墨に満ちた虎の腹の中だ。","ENG":"This is the Tiger's belly, filled to the brim with Ink.","TWN":"這裡是被墨充滿的老虎肚子裡。"},"stage":{"bg":"VOID","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L10_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"VOID","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L11_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"보여선 안 될 것이 보이는데, 내가 아직도 꿈을 꾸는 거요?","JPN":"見えるはずのない存在が見えるのだが、某はまだ夢を見ているのか？","ENG":"I'm seeing something that shouldn't exist… Am I still dreaming?","TWN":"看到了不該看的東西，我還在做夢嗎？"},"stage":{"bg":"VOID","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L12_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"네 혼백이 녹아내려 먹과 하나될 때까지, 영영 꿈만 꿀 수도 있었을 테지.","JPN":"お前の魂魄が溶け落ち墨と一つになるまで、永遠に夢を見ることだってできたわけだが……","ENG":"You might have dreamed forever until your soul melted away and merged with the Ink.","TWN":"在你的魂魄融化與墨合為一體之前，你本來可以永遠做夢下去。"},"stage":{"bg":"VOID","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"그래도 깨어난 것을 보면, 내가 남겨논 문장이 쓸모는 있었던 모양이구나.","JPN":"それでも目覚めたということは、俺が残した文はちゃんと役に立ったようだな。","ENG":"But since you've woken, I suppose the text I left behind did its job.","TWN":"不過看你醒了，看來我留下的文字還是有點用處。"},"stage":{"bg":"VOID","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L14_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"정말 살아있는 사람이 맞소?","JPN":"本当に生きている人間なのか？","ENG":"Are you truly alive?","TWN":"你真的是活人嗎？"},"stage":{"bg":"VOID","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L15_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"정녕 네놈 앞에 있는 게 창귀로 보이느냐?","JPN":"お前の目の前にいるのが、倀鬼に見えるか？","ENG":"Do I look like a ghost thrall to you?","TWN":"你真的把眼前的我當成是倀鬼嗎？"},"stage":{"bg":"VOID","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L16_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"…명달 대장이 창귀였다면, 지금쯤 내 두 눈을 찔렀겠지.","JPN":"……アカタツ隊長が倀鬼になったら、今頃某の両目は刺されていたであろう。","ENG":"…If you were one, you'd have gouged out my eyes by now.","TWN":"…如果明達隊長是倀鬼，現在早就刺瞎我的雙眼了。"},"stage":{"bg":"VOID","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L17_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"난… 대장이 죽은 줄로만 알았소.","JPN":"某は……隊長は死んだのだと思っていた。","ENG":"I thought… you were dead.","TWN":"我…還以為隊長已經死了。"},"stage":{"bg":"VOID","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L18_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"내 말하지 않았느냐? 호랑이 뱃속에 들어가도 정신만 차리면…","JPN":"だから言っただろう？　虎に食われても気をしっかり保てば……","ENG":"Didn't I tell you? Even if I end up in its belly, so long as I keep my wits…","TWN":"我不是說過嗎？就算進了老虎肚子裡，只要打起精神…"},"stage":{"bg":"VOID","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"…10년은 버티는 법이라고 하셨지.","JPN":"……10年は行ける、とな。","ENG":"…That you'd hold out for ten years.","TWN":"…就能撐十年，你是這麼說的。"},"stage":{"bg":"VOID","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"범의 뱃속에선 먹힌 자의 살아온 세월이 놈의 양분이 된다.","JPN":"虎の腹の中では、食われた者の生きた年月がやつの糧となる。","ENG":"Within the Tiger's belly, your years lived become its nourishment.","TWN":"在老虎肚子裡，被吞者的歲月會成為牠的養分。"},"stage":{"bg":"VOID","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L21_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"보통 사람이라면 며칠 새로 먹이 되었겠지만, 내 살아온 세월을 전부 놈의 양분으로 삼으려면 족히 10년은 걸리지.","JPN":"普通の人間なら数日で墨になっていただろうが、俺の生きてきた時間をすべてやつの糧に変えるには、10年はかかる。","ENG":"A normal person would've been digested into Ink in days, but it'd take at least ten years to digest the whole of my life.","TWN":"普通人可能幾天內就會變成飼料，但要將我活過的歲月全部當成養分，大概得花上十年。"},"stage":{"bg":"VOID","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"과연, 허투루 하는 말씀이 아니었구려.","JPN":"なるほど、適当な話ではなかったのだな。","ENG":"So you weren't bluffing after all.","TWN":"果然，你的話從來都不是隨口說說。"},"stage":{"bg":"VOID","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"허나 내가 아무리 버텨낸다 한들, 네놈이 오지 않았다면 난 깨어나지 못했을 거다.","JPN":"しかし俺がいくら耐えられたところで、お前が来てくれなかったら目覚めることはできなかっただろう。","ENG":"Still, no matter how long I held out, I wouldn't have awakened if you hadn't come.","TWN":"然而，就算我再怎麼撐，如果不是你來，我也不可能醒來。"},"stage":{"bg":"VOID","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"…잘 해주었구나.","JPN":"……よくやってくれた。","ENG":"…You did well.","TWN":"…你做得很好。"},"stage":{"bg":"VOID","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L25_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"VOID","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L26_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"고맙소. 본인을 믿고 견뎌주어서.","JPN":"感謝する。某を信じて耐えてくれて。","ENG":"Thank you. For enduring and believing in me.","TWN":"謝謝你。相信我並撐下來。"},"stage":{"bg":"VOID","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L29_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"그럼 가자꾸나.","JPN":"では行こうか。","ENG":"Then let's be off.","TWN":"那麼走吧。"},"stage":{"bg":"VOID","bgm":"THEMA_CA_CLOUD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_COMBAT_ALL_SWORD_MOVEMENT"},{"id":"L30_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"아늑한 꿈을 벗어나 지옥 같은 현실을 마주할 준비는 되었느냐?","JPN":"心地良い夢から出て、地獄のような現実と向き合う覚悟はできているか？","ENG":"Are you ready to leave your cozy dream behind and face a living hell?","TWN":"準備好離開舒適的夢境，面對如同地獄般的現實了嗎？"},"stage":{"bg":"VOID","bgm":"THEMA_CA_CLOUD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"꿈 같은 건, 이제 지긋지긋하다네.","JPN":"夢はもう懲り懲りだ。","ENG":"I'm sick of dreams.","TWN":"夢這種東西，我已經受夠了。"},"stage":{"bg":"VOID","bgm":"THEMA_CA_CLOUD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"VOID","bgm":"THEMA_CA_CLOUD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L38_1","type":"narration","speaker":null,"text":{"KOREA":"네놈들이 지금, 내 배를 뚫고 나온 것이냐?","JPN":"吾輩の腹を突き破って出て来たのか。","ENG":"So you've clawed your way out of my belly, have you?","TWN":"你們現在，是打穿了我的肚子出來的嗎？"},"stage":{"bg":"BLACKMOUNTAIN_1","bgm":"THEMA_CA_CLOUD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"그 창자 냄새는 역하기가 짝이 없더군.","JPN":"お前の腸、吐き気がする匂いだったぞ。","ENG":"The stench of your guts is something else.","TWN":"那股腸子味真是噁心得要命。"},"stage":{"bg":"BLACKMOUNTAIN_1","bgm":"THEMA_CA_CLOUD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L41_1","type":"narration","speaker":null,"text":{"KOREA":"왜 아직도 살아있는 것이지?","JPN":"なぜまだ生きている？","ENG":"Why are you still alive?","TWN":"為什麼你們還活著？"},"stage":{"bg":"BLACKMOUNTAIN_1","bgm":"THEMA_CA_CLOUD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"narration","speaker":null,"text":{"KOREA":"제아무리 길게 산 망량의 피라 한들 그 안에서 10년을 넘게 버틸 재간은 없을 텐데?","JPN":"いかに長生の魍魎の血を持つとはいえ、あの中で10年以上を耐えるなど叶うまい。","ENG":"Even with the long-lived Mangryang Blood in your veins, no one lasts over ten years in there.","TWN":"就算再怎麼長壽的魍魎之血，也不可能在裡面撐過十年吧？"},"stage":{"bg":"BLACKMOUNTAIN_1","bgm":"THEMA_CA_CLOUD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"허허, 거사에 정신이 팔려 작은 것을 간과했구나.","JPN":"はは、大事に気を取られ、細事を見過ごしたな。","ENG":"Haha, you got so caught up in your grand design, you missed a small detail.","TWN":"哈哈，太過專注於大事，反而忽略了小事。"},"stage":{"bg":"BLACKMOUNTAIN_1","bgm":"THEMA_CA_CLOUD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"네놈이 서생을 속여 현실을 개변한 순간, 그 10년도 처음부터 헤아려야 한단 것을.","JPN":"お前がショウを騙して現実を改変した瞬間、そこからの10年も改めて考え直さなければならないことを。","ENG":"The moment you tricked Seosaeng and changed reality, the clock started ticking from the beginning again.","TWN":"當你騙過書生改變現實的那一刻，那十年也必須從頭計算。"},"stage":{"bg":"BLACKMOUNTAIN_1","bgm":"THEMA_CA_CLOUD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L46_1","type":"narration","speaker":null,"text":{"KOREA":"바라는 이상 속에서 이 몸과 하나 될 기회를 주었거늘- 본좌의 몽상을 거스르고 깨어나다니.","JPN":"描く理想の中で吾輩と一つになる機会を与えてやったというのに、吾輩の夢想に逆らい目を覚ますとは。","ENG":"I gave you the chance to become one with me, in the ideal world you longed for. And yet you chose to defy my dream and awaken.","TWN":"明明給了你們在我所希望的理想中，與這身軀合而為一的機會，但你們居然反抗本座的期待，選擇醒來。"},"stage":{"bg":"BLACKMOUNTAIN_1","bgm":"THEMA_CA_CLOUD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BELL6"},{"id":"L47_1","type":"narration","speaker":null,"text":{"KOREA":"어리석은 중생들이로다.","JPN":"愚かなやつめ。","ENG":"Foolish creatures.","TWN":"真是愚蠢的眾生。"},"stage":{"bg":"BLACKMOUNTAIN_1","bgm":"THEMA_CA_CLOUD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"그런 어리석은 중생이기에-","JPN":"そんな愚かなやつだからこそ……","ENG":"That's exactly why…","TWN":"正因為是如此愚蠢的眾生—"},"stage":{"bg":"BLACKMOUNTAIN_1","bgm":"THEMA_CA_CLOUD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"잡히는 것 없는 꿈에서 누릴 천수 보다, 뜻대로 살아갈 하루를 택하는 법 아니겠나?","JPN":"泡沫の夢の中で長生を享受するより、思うがままに過ごす一日を選ぶものだろう。","ENG":"We'd choose a single day lived on our terms over a good, long lifetime in someone else's dream.","TWN":"才會捨棄在虛幻的夢中享樂的壽命，選擇能夠隨心所欲過活的一天不是嗎？"},"stage":{"bg":"BLACKMOUNTAIN_1","bgm":"THEMA_CA_CLOUD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"어떠신가요?","JPN":"どうですか？","ENG":"So, what do you think?","TWN":"感覺如何？"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"당신의 혈맥을 이어받은 우리의 작품이.","JPN":"私たちが作り上げた、君の血を受け継いだこの作品が。","ENG":"Of the creation born from your bloodline.","TWN":"這是我們的作品，她繼承了你的血脈。"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"이 아이가 내 피를 이어받았다는 게요?","JPN":"この子が俺の血を引いていると？","ENG":"You're saying this child carries my blood?","TWN":"這孩子繼承了我的血脈？"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"참으로… 신기하군. 오래 살고 볼 일이야.","JPN":"実に……不思議だな。長生きはしてみるものだな。","ENG":"How strange… Live long enough, and you see it all.","TWN":"真是…稀奇。人生在世真是無奇不有。"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"한 달 뒤면 배양실을 떠나 적응 훈련을 시작할 거에요.","JPN":"1か月後には培養室を出て、適応訓練を始めます。","ENG":"In a month, she'll leave the incubation chamber and begin adaptation training.","TWN":"一個月後，她就會離開培養室，開始適應訓練。"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"명달과 같은 재능을 타고났다면, 금방 실전 전투에 투입될 수 있겠죠.","JPN":"アカタツと同じ才能を生まれ持っているなら、すぐに実戦に参加できるでしょう。","ENG":"If she has your talents, she'll be in live combat soon enough.","TWN":"如果她天賦與明達相同，很快就能投入實戰。"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"죽음을 두려워 않는 한 명의 검사로서.","JPN":"死を恐れない一人の剣士として。","ENG":"As a swordswoman unafraid of death.","TWN":"作為一個不畏懼死亡的劍士。"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"…이해했네.","JPN":"……理解した。","ENG":"…I see.","TWN":"…我明白了。"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"관리국의 전력에 보탬이 된다면, 앞으로도 얼마든지 협력하리다.","JPN":"管理局の戦力に貢献できるなら、今後もいくらでも協力しよう。","ENG":"If she can serve the Administration, I'll gladly lend my support again.","TWN":"如果能對管理局的戰力有所助益，我今後也願意隨時合作。"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"한동안은 못 뵐 텐데, 더 궁금한 건 없으신가요?","JPN":"しばらくは会えなくなりますが、他に気になることはありませんか？","ENG":"We won't be seeing each other for a while. Any questions before I go?","TWN":"有一陣子見不到面了，你還有什麼想知道的嗎？"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"저 아이 이름. 어찌 부르는가?","JPN":"あの子の名前は何と言う？","ENG":"What's her name?","TWN":"那孩子的名字。該怎麼稱呼？"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_SERIOUS2"},"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"아직 정해진 건 아무것도 없어요.","JPN":"まだありません。","ENG":"She doesn't have one yet.","TWN":"還沒決定。"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"훗날 어느 부대에 배치되느냐에 따라 코드가 정해지겠죠.","JPN":"後日配属される部隊によって、コードが決まるでしょう。","ENG":"She'll get a code once she's assigned to a unit.","TWN":"日後被分發到哪個部隊，就會決定代號。"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"…이름 석 자 정돈 있어도 나쁘지 않을 텐데 말이오.","JPN":"……本名ぐらいはあっても悪くないと思うがな。","ENG":"…A name wouldn't hurt.","TWN":"…有個名字總比沒有好。"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"너무 정을 붙이진 마세요, 명달.","JPN":"あまり思い入れはしないことです、アカタツ。","ENG":"Don't grow too attached, Myeongdal.","TWN":"別太過投入感情，明達。"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"양산화 단계에 접어들기 전까진, 이 초기 모델에서 어떤 문제점이 발견될지 몰라요.","JPN":"量産化段階に入るまでは、このプロトタイプからどんな不具合が見つかるか分かりません。","ENG":"Until mass production begins, we don't know what flaws might show up in the prototypes.","TWN":"在進入量產階段之前，誰也不知道這個初期模型會發現什麼問題。"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"다른 사람도 아닌, <color=#ffd34c>당신</color>을 본떠 만들어진 존재니까요.","JPN":"他でもない、<color=#ffd34c>君</color>を模して作られた存在なのですから。","ENG":"Especially since she was modeled after <color=#ffd34c>you</color>.","TWN":"畢竟，她是以你為藍本製造出來的存在。"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"상부는… 이 아이에 대해 얼마나 알고 있나?","JPN":"上層部は……この子についてどこまで知っている？","ENG":"How much… does the upper command know about her?","TWN":"上層…對這孩子了解多少？"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"애초에 보고하지 않았어요. 여기까지 오려고 어긴 금기가 한둘이 아니니까.","JPN":"そもそも報告していません。ここまで来るために、いくつも禁忌を犯していますから。","ENG":"They weren't informed. I've broken more than a few taboos getting this far.","TWN":"我一開始就沒報告。為了走到這一步，我違反的禁忌可不只一兩個。"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"이 사실이 알려진다면, 분명 폐기 수순을 밟게 되겠죠.","JPN":"この事実が知られたら、きっと廃棄処分になるでしょう。","ENG":"If word gets out, she'll be scrapped for sure.","TWN":"如果這件事被發現，肯定會被廢棄。"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"이 비밀은 반드시 새어나가는 일이 없게 하겠소.","JPN":"この秘密は必ず守るとしよう。","ENG":"Then I'll make sure that never happens.","TWN":"我會確保這個秘密絕對不會外洩。"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"TRAINER_NPC_NULL_NULL","text":{"KOREA":"말씀하신대로입니다. 유달리 검술 실력이 뛰어난 훈련생이 있죠.","JPN":"おっしゃるとおりです。ひときわ剣術の腕が優れた訓練生がいますね。","ENG":"Just like you said. We've got one trainee with exceptional sword skills.","TWN":"正如你所說。有個劍術實力特別出色的訓練生。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"TRAINER_NPC_NULL_NULL","text":{"KOREA":"성격이 유별나서 베테랑 카운터 출신인 줄 알았는데, 만들어진 지 얼마 안된 친구더군요.","JPN":"変わった性格で、ベテランカウンター出身かと思ったら、作られて日が浅い子でした。","ENG":"Thought she was a veteran Counter at first, but turns out she's brand new.","TWN":"個性很特別，我還以為是資深的制裁者，結果是個剛被製造出來沒多久的傢伙。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"JISOO_NPC_PAST_14","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":"JISOO_NPC_PAST_14","text":{"KOREA":"언제까지 그러고 있을 셈이지? 늙은이.","JPN":"いつまでそうしているつもりだ、老いぼれ。","ENG":"How long are you planning to just stand there, old man?","TWN":"你打算就這樣待到什麼時候？老頭。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"오, 날 본 게냐?","JPN":"おお。俺を見たのか？","ENG":"Oh? You noticed me?","TWN":"喔，你看到我了嗎？"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"오늘은 조용히 지켜보기만 할 생각이었는데.","JPN":"今日は静かに見守るつもりだったがな。","ENG":"I was planning to quietly observe today.","TWN":"我今天本來只想安靜地觀察。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"JISOO_NPC_PAST_14","text":{"KOREA":"당신 같은 사람은 이미 많이 봐왔어.","JPN":"お前のような人間はたくさん見てきた。","ENG":"I've seen your type plenty.","TWN":"你這種人我見多了。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"JISOO_NPC_PAST_14","text":{"KOREA":"날 전대로 데려가니 마니, 맡겨 논 물건 고르듯 따져대는 족속들 말이야.","JPN":"私を戦隊に連れて行くだのなんだの、商品を選ぶようにあれこれ聞いてくる連中のことだ。","ENG":"The ones who treat me like goods to be inspected before deployment.","TWN":"你是不是在想要不要把我送到前線，挑三揀四地像是在買東西一樣。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"JISOO_NPC_PAST_14","text":{"KOREA":"그런데 당신은 이미 열흘도 넘게 지켜봤으면서 말 한 마디 붙이지 않는군.","JPN":"だが、お前は10日以上私を見ていたくせに、声の一つもかけなかった。","ENG":"But you've been watching for over ten days and haven't said a word.","TWN":"但是你已經觀察十多天了，卻連一句話都沒說。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"관리국에서 널 데려갈 만한 권한이 있는 자라면, 널 물건이라 생각하진 않을 게다.","JPN":"管理局でお前をつれて行けるほどの権限を持つ者なら、お前を商品扱いなんてしないだろう。","ENG":"Anyone with authority to take you in the Administration wouldn't see you as a mere object.","TWN":"管理局裡有權帶走你的人，不會把你當成物品。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"그들의 성품은 내가 보증하마.","JPN":"彼らの品性は俺が保証する。","ENG":"I can vouch for their character.","TWN":"他們的人品我可以保證。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"JISOO_NPC_PAST_14","text":{"KOREA":"내가 궁금한 건 그 자들의 성품이 아니라, 당신이 날 쳐다보기만 하는 이유야.","JPN":"私が気になるのはやつらの品性ではない。お前が私を見ている理由だ。","ENG":"I'm not interested in their character. I want to know why you're just staring at me.","TWN":"我想知道的不是他們的人品，而是你為什麼只是看著我。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"그게, 요즘 새로 생긴 내 취미라서.","JPN":"最近できた俺の趣味だ。","ENG":"Guess it's a new hobby of mine.","TWN":"那是，我最近新養成的嗜好。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"불쾌했다면 다신 오지 않도록 하마.","JPN":"不愉快なら、二度と来ないようにしよう。","ENG":"But if I made you uncomfortable, I won't come again.","TWN":"如果你感到不舒服，那我下次就不會再來了。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"JISOO_NPC_PAST_14","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"JISOO_NPC_PAST_14","text":{"KOREA":"가까이 오지 않는 게 좋다고, 충고하려 했을 뿐이야.","JPN":"近づかないほうがいいと、忠告しようとしただけだ。","ENG":"I was going to warn you to keep your distance.","TWN":"我只是想勸你，最好不要靠近我。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"JISOO_NPC_PAST_14","text":{"KOREA":"내 눈엔 보여선 안 될 게 보이거든.","JPN":"私の目には、見えてはならないものが見える。","ENG":"My eyes see things that shouldn't be seen.","TWN":"因為我的眼睛能看到不該看的東西。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"그 눈에 다른 사람의 죽음이 보이느냐?","JPN":"その目に、他人の死が映るのか？","ENG":"Do you see people's deaths?","TWN":"你的眼睛能看到別人的死亡嗎？"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"JISOO_NPC_PAST_14","text":{"KOREA":"뭐…? 그걸 어떻게?","JPN":"なっ……？　なぜそれを？","ENG":"What…? How did you know that?","TWN":"什麼…？你怎麼知道？"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"들여다보지 않았는데도 죽음이 보이는 게로군.","JPN":"覗こうとしなくても死が見えるのだな。","ENG":"You see it even without trying.","TWN":"沒有刻意去看，卻能看到死亡。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"이것이 박사가 우려한 문제점인가.","JPN":"これが博士が懸念していた問題点なのか。","ENG":"So this is what the doctor was worried about.","TWN":"這就是博士擔心的問題嗎？"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"JISOO_NPC_PAST_14","text":{"KOREA":"박사…? 율리아 박사를 말하는 건가?","JPN":"博士……？　ユリア博士のことか？","ENG":"Doctor…? You mean Dr. Yulia?","TWN":"博士…？你說的是茱莉亞博士嗎？"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"JISOO_NPC_PAST_14","text":{"KOREA":"당신, 정체가 뭐지? 내 앞에 나타난 목적이 뭐야!","JPN":"お前、何者だ？　何の目的で私の前に現れた？","ENG":"Who are you? What do you want from me?!","TWN":"你到底是什麼人？出現在我眼前的目的是什麼！"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"JISOO_NPC_PAST_14","text":{"KOREA":"대답해! 왜 내 눈에 대해 알고 있는 거냐고!","JPN":"答えろ！　なぜこの目について知っている！","ENG":"Answer me! How do you know about my eyes?","TWN":"回答我！你為什麼會知道我的眼睛！"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L16_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"많이 힘들었겠구나. 꼬마야.","JPN":"大変だっただろう？","ENG":"You must have been through a lot, kid.","TWN":"你一定很辛苦吧，小丫頭。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"JISOO_NPC_PAST_14","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"원치 않았던 누군가의 마지막을 본다는 건, 썩 유쾌하지 않은 일이지.","JPN":"望んでなくても他人の最期を見てしまうのは、あまり気分のいいことではない。","ENG":"Seeing someone's end you never asked for isn't exactly delightful.","TWN":"目睹某個人不願面對的最後結局，可不是什麼令人愉快的事。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"JISOO_NPC_PAST_14","text":{"KOREA":"나와 함께 훈련받던 동료들이…","JPN":"私と共に訓練を受けていた仲間たちが……","ENG":"The other comrades I trained with…","TWN":"和我一起訓練的同伴們…"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"JISOO_NPC_PAST_14","text":{"KOREA":"내 눈에 박힌 그 끔찍한 광경들이… 정말로 헛것이 아니라고?","JPN":"私の目に映ったあの悲惨な光景は……本当に幻じゃなかったのか？","ENG":"The horrible visions burned into my eyes… They weren't hallucinations?","TWN":"那些映入我眼中的可怕景象…真的不是幻覺嗎？"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_SILHOUETTE","text":{"KOREA":"견뎌내라곤 하지 않으마.","JPN":"何も、耐えろとは言わない。","ENG":"I won't tell you to endure it.","TWN":"我不會要你忍耐。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_SILHOUETTE","text":{"KOREA":"적어도, 앞으로 벌어질 모든 일들이 네 탓이 아니란 것만 알아다오.","JPN":"せめて、これから起きるすべてがお前のせいではないということだけ、覚えていてくれ。","ENG":"Just remember that none of what's coming is your fault.","TWN":"但至少，請你知道，今後發生的所有事情，都不是你的錯。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"narration","speaker":null,"text":{"KOREA":"내 탓이 아니라고?","JPN":"私のせいじゃない？","ENG":"Not my fault?","TWN":"不是我的錯？"},"stage":{"bg":"WHITE","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"narration","speaker":null,"text":{"KOREA":"이 낯선 기억들은 대체 뭐지?","JPN":"この見覚えのない記憶は何だ？","ENG":"What exactly are these strange memories?","TWN":"這些陌生的記憶到底是怎麼回事？"},"stage":{"bg":"WHITE","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"정보 오염.","JPN":"情報汚染。","ENG":"Data corruption.","TWN":"資訊污染。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"그 모든 것들을 겪기 이전의 당신 과거일 거에요.","JPN":"そのすべてを経験する前の、あなたの過去よ。","ENG":"They're probably fragments from your past before all this happened.","TWN":"那會是你經歷所有事情之前的過去。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"넌… 창귀?","JPN":"お前は……倀鬼？","ENG":"You're… a ghost thrall?","TWN":"你是…倀鬼？"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"왜 내가 네 녀석과 대화를 나누고 있는 거지? 여긴 대체 어디냐!","JPN":"なぜ私がお前と話している？　ここはいったいどこだ！","ENG":"Why am I talking to you? Where even is this place?","TWN":"我為什麼會和你在說話？這裡到底是哪裡！"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"정확한 이름 같은 건 없지만… 일단은 심상세계의 말로라고 해두죠.","JPN":"正確な名前などはないけれど……一応、心象世界ということにしておきましょう。","ENG":"No official name… but you can call it a mental world.","TWN":"雖然沒有確切的地名…但暫且稱之為心象世界吧。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"이곳은 범이 먹어 치우고 남긴, 감정과 사념이 잠시 머무는 공간이랍니다.","JPN":"ここは虎に食らいつくされた後に余った、感情や思念がしばらく留まる空間です。","ENG":"It's a space where remnants of thoughts and emotions devoured by the Tiger linger briefly.","TWN":"這裡是老虎吞噬後留下的，情感和思念暫時停留的空間。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"그렇다면 난 죽은 건가?","JPN":"なら、私は死んだのか？","ENG":"So that means I'm dead?","TWN":"那我是死了嗎？"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"아마 그렇지 않을까요?","JPN":"多分そうじゃないでしょうか？","ENG":"Most likely, yes.","TWN":"大概吧？"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L39_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"그리고 지금 이렇게 뒤엉켜 대화를 나누는 우리 두 사람의 사념도, 머잖아 연기처럼 사라질 거에요.","JPN":"そして今こう、絡み合って言葉を交わしている私たちの思念も、もうすぐ煙のごとく消えてしまうでしょう。","ENG":"And the lingering thoughts of us, tangled in this conversation, will eventually fade too.","TWN":"而現在這樣糾纏在一起交談的我們兩人的思念，不久後也會像煙霧一樣消失。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"너도 제대로 아는 게 없다는 것처럼 지껄이는군.","JPN":"自分も詳しいことは分からないといった物言いだな。","ENG":"You talk like you barely know what's going on either.","TWN":"你說話的樣子，好像自己也不太清楚。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_HATE"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"얼마 전까지만 해도 우릴 전부 죽이려 한 주제에 말이야.","JPN":"少し前までは私たちを殺しにかかっていたくせに。","ENG":"Not to mention you tried to kill us all not too long ago.","TWN":"明明不久前還想把我們全部殺光。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L43_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"당신의 말대로, 제 혼백은 범의 뜻대로 이용당하고 있어요. 거기에 난 아무 간섭도 할 수 없죠.","JPN":"あなたの言う通り、私の魂魄は虎の意のままに利用されています。私はそこに何の干渉もできない。","ENG":"You're not wrong. My soul's being used just as the Tiger intended. I have no control over it.","TWN":"正如你所說，我的魂魄被老虎利用了。我無法干涉。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"단지 당신처럼 과거를 추억하며, 희미해져 가는 기억에 매달리는 감정의 파편일 뿐.","JPN":"ただあなたのように過去を振り返り、薄れていく記憶にすがる、感情の破片にすぎない。","ENG":"All that remains is a shard of emotion clinging to fading memories, just like you.","TWN":"只不過是像你一樣，追憶過去、緊抓著逐漸模糊的記憶所殘留的情感碎片。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_HATE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"어째서냐?","JPN":"なぜだ？","ENG":"Why?","TWN":"為什麼？"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"어째서 범을 잡기 위해 네 자신을 희생한 거지?","JPN":"なぜ虎を倒すために自分を犠牲にした？","ENG":"Why did you throw yourself away just to take down the Tiger?","TWN":"為什麼為了抓老虎而犧牲自己？"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"명달 대장은 점괘로 운명을 점치거든요. 자신의 힘만으론 범을 이길 수 없다는 걸 일찍이 알고 있었어요.","JPN":"アカタツ隊長は、占いを通じて運命を見抜きます。自分の力だけでは虎に勝てないということを、最初から知っていました。","ENG":"Commander Myeongdal always read fate through fortunes. He saw from the start that he alone wouldn't be enough to win against the Tiger.","TWN":"明達隊長會用卜卦來預測命運。他早就知道憑自己的力量無法戰勝老虎。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"그래서 돕겠다고 나선 건가?","JPN":"だから助けに出たのか？","ENG":"So you decided to help?","TWN":"所以你決定幫助他嗎？"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"그를 도와 범의 목을 벨 사람이 필요했으니까요.","JPN":"誰かは彼を手伝い、虎の首を斬る必要があったから。","ENG":"Someone had to stand with him and cut the Tiger down.","TWN":"因為總要有人幫助他斬下老虎的頭顱。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"결정을 내렸을 땐, 그 다음 일 같은 건 생각하지 않았답니다.","JPN":"心を決めた時、後のことなど考えていませんでした。","ENG":"And when I made that choice, I didn't really think about what would come next.","TWN":"做出決定時，我沒想過之後的事情。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"결국 꼴사납게 져서 범에게 부려지는 꼴이 되었으니… 내가 어리석었죠.","JPN":"結局無様に敗北し、虎に従わされる羽目になったのだし……愚かでしたね。","ENG":"But in the end, I lost. I was defeated and turned into a pawn of the Tiger… I was a fool.","TWN":"結果狼狽地輸了，還被老虎利用…是我太傻了。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"넌 서생이 돕겠다는 말에도 들은 채 않고 그자를 밀어냈어.","JPN":"お前はショウが助けると言ってきたのに、聞く耳持たずに彼を拒んだ。","ENG":"Even when Seosaeng offered to fight with you, you pushed him away.","TWN":"你明明把書生推開，連他想幫忙的話都聽不進去。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"},"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"그 고집을 부리지만 않았어도, 결과가 달라졌을 거란 생각은 안 하나?","JPN":"意地を張らず素直に受け入れたら、結果が変わったかもしれないと思わないか？","ENG":"Don't you ever wonder how things would've ended differently if you hadn't been so stubborn?","TWN":"你沒有想過，如果你沒有那麼固執，結果會不會有所不同？"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"이미 다 지나고 후회한들, 무슨 소용이 있는데요?","JPN":"過ぎたことを後悔して何になります？","ENG":"It's too late for regrets now, isn't it?","TWN":"都已經過去了，後悔又有什麼用？"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"다 지났다고?","JPN":"過ぎた？","ENG":"Too late?","TWN":"過去了？"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_SERIOUS"},"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"서생은 몇 번씩이나 널 도우려 했다. 온 재산을 탕진하고, 침식체와 몇 번씩이나 부딪혀가며, 널 만나기 위해 목숨까지 걸었다고!","JPN":"ショウは何度もお前を助けようとした。全財産を注ぎ込み、侵食体と何度も戦い、お前に会うために命を賭けたんだ！","ENG":"Seosaeng tried to help you over and over again. He used up all his money. Faced C.O.s again and again. He put his life on the line just to see you one more time!","TWN":"書生好幾次都想幫助你。他花光了所有財產，好幾次與侵蝕體對抗，為了見到你不惜冒上性命危險！"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L9_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"그게 운명이라는 거에요. 아무리 노력하고 시간을 되돌려도 결코 변치 않는 것이라고요.","JPN":"それが運命なのです。いくら頑張って時間を巻き戻したところで、決して変わらない。","ENG":"That's fate. No matter how hard you try or how far you turn back time, some things will never change.","TWN":"那就是命運。無論怎麼努力，怎麼回到過去，都無法改變的東西。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_HATE"},"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"나도… 서생과 함께 하고 싶었어요.","JPN":"私だって……ショウと共にいたかった。","ENG":"I also… wanted to be with Seosaeng.","TWN":"我也…想和書生在一起。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L13_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"죽더라도 그 사람과 함께였다면… 한 같은 건 품지 않았겠죠.","JPN":"死んでもあの人と一緒なら……無念を抱えることだってなかった。","ENG":"If I had been with him when I died… maybe I wouldn't have had a grudge.","TWN":"就算死了，如果能和他在一起…我也不會有遺憾。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"죽고 난 뒤에도 그렇게 비밀스러운 사람처럼 굴 건가?","JPN":"死んだ後も、そうやって事情ありげな態度をとるつもりか？","ENG":"Still keeping secrets, even after death?","TWN":"死後你也要這麼神祕嗎？"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"},"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"이유가 있다면 지금이라도 그 이유를 속 시원하게 말해.","JPN":"理由があるなら、今からでも全部打ち明けろ。","ENG":"If there's a reason, then just spit it out. Right now.","TWN":"如果有什麼原因，現在就說出來。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"대체… 뭐가 널 그렇게 만든 건지.","JPN":"いったい……何がお前をそうしたのか。","ENG":"What… made you this way?","TWN":"到底…是什麼讓你變成這樣。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"너는 네 생애 가장 행복한 순간에 재앙을 맞닥뜨려 죽을 팔자다.","JPN":"お前は、人生で最も幸せな瞬間に災害に遭遇して死ぬ運命だ。","ENG":"Your fate is to die at the happiest moment of your life.","TWN":"你的命運註定在人生最幸福的時刻遭遇災難而死。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_09","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"네 곁의 가장 소중한 사람들과 함께 말이야.","JPN":"お前の側にいる最も大切な人々と共にな。","ENG":"And with you, all the people you love most too.","TWN":"與你身邊最重要的人一起。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_09","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"그건…","JPN":"それは……","ENG":"That means…","TWN":"那…"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_09","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L22_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"무슨 수를 써도 피할 수 없는 운명인 거죠?","JPN":"どんな手を使っても、逃れられない運命なのですね？","ENG":"No matter what I do, there's no escaping fate?","TWN":"是無論如何都無法避免的命運吧？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_09","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"…그래.","JPN":"……ああ。","ENG":"…Yes.","TWN":"…沒錯。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_09","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"그것이 용혈이 품은 저주이니라.","JPN":"それが龍血に宿る呪いだ。","ENG":"That is the curse carried in the Dragon Blood.","TWN":"那是龍血所蘊含的詛咒。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_09","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"허나, 짐승에 맞서려면 혈맥은 이어져야 하는 것이기에… 이를 누구에게도 알리지 않았다.","JPN":"しかし、ケモノに立ち向かうために血脈は受け継がれる必要がある……故にこれは誰にも知らせていない。","ENG":"But to fight the Beast, that bloodline must continue… That's why I told no one.","TWN":"然而，為了對抗野獸，血脈必須延續…所以我從未告訴任何人。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_09","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"모든 것에 통달한 최고관리자조차, 긴 세월 속 거듭되는 운명을 지켜보며 짐작만 할 뿐이지.","JPN":"すべてお見通しの最高管理者さえ、長い時間繰り返される運命を見て薄っすらと察しているだけだ。","ENG":"Even the Administrator, who claims mastery over all, could only watch and guess as fate repeated over a long time.","TWN":"連通曉一切的最高管理者，也只能在漫長的歲月中，看著反覆的命運而猜測。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_09","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"그럼 전…","JPN":"なら、私は……","ENG":"So then…","TWN":"那我是…"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_09","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"그 사람과는 영원히 행복할 수 없는 운명인 거네요.","JPN":"あの人とは、永遠に幸せになれない運命なんですね。","ENG":"That means I can never be happy with him, by fate. Not ever.","TWN":"注定無法和那個人永遠幸福的命運。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_09","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"죽음은 영원한 망각과 같으니, 그마저도 잊게 되겠지.","JPN":"死は永遠の忘却のようなもの。それすらも忘れることになるだろう。","ENG":"Death is like eternal forgetting. You'll forget even that, in time.","TWN":"死亡就像永遠的遺忘，連那也會忘記吧。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_09","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"운명을 넘어서… 누군가 그 용혈의 저주를 끊어낼 때까지.","JPN":"運命を超えて……誰かがその龍血の呪いを断ち切るまでは。","ENG":"Unless someone breaks the Dragon Blood's curse… and ends this fate once and for all.","TWN":"直到…有人超越命運，斬斷那龍血的詛咒。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_09","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"그런 날이 올까요?","JPN":"そんな日が来るんでしょうか？","ENG":"Do you think that day will ever come?","TWN":"會有那一天嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_09","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"글쎄. 나도 그럴 거라 말하고는 싶지만…","JPN":"さあな。来ると言いたいところだが……","ENG":"Well, I'd like to say yes…","TWN":"說不好。我也想說會…"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_09","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"적어도 내 운명이 허락하는 마지막 순간까진, 그런 미래가 보이지 않더구나.","JPN":"少なくとも俺の運命が許す最後の瞬間までは、そんな未来は見えなかった。","ENG":"But at least from where I stand, I've never seen a future where that happens.","TWN":"但至少在我命運允許的最後一刻，我沒有看到那樣的未來。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_09","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"얼른 가죠, 대장.","JPN":"早く行きましょう、隊長。","ENG":"Then let's go, Commander.","TWN":"快走吧，隊長。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_09","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"운명을 넘어선다는 건, 점괘로도 알 수 없는 미래란 뜻이잖아요.","JPN":"運命を超えるということは、占いでも分からない未来だということでしょう。","ENG":"To go beyond fate means stepping into a future even fortunes can’t predict.","TWN":"超越命運，意思就是連卜卦都無法預測的未來。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_09","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"분명, 지금이 그 운명을 끊어낼 순간일 지도 모른다구요.","JPN":"今が、その運命を断ち切る瞬間かもしれません。","ENG":"Maybe this is our chance to end that fate.","TWN":"說不定，現在就是斬斷命運的時刻。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_09","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_09","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"그래… 가자꾸나.","JPN":"ああ……行こう。","ENG":"Very well… Let's go.","TWN":"好…走吧。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_09","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};